<template>
  <div class="home">
    <div class="result">
      <div v-for="(v, i) in dataList" :key="i">
        <div class="pos1">
          <span v-for="(v1, i1) in Object.keys(v.data.pos1)" :key="i1"
            >{{ v.data.pos1[v1] }}<br
          /></span>
        </div>
        <div class="pos2">
          <span v-for="(v2, i2) in Object.keys(v.data.pos2)" :key="i2"
            >{{ v.data.pos2[v2] }}<br
          /></span>
        </div>
        <div class="pos3">
          <span v-for="(v3, i3) in Object.keys(v.data.pos3)" :key="i3"
            >{{ v.data.pos3[v3] }}<br
          /></span>
        </div>
        <div class="pos4">
          <span v-for="(v4, i4) in Object.keys(v.data.pos4)" :key="i4"
            >{{ v.data.pos4[v4] }}<br
          /></span>
        </div>
        <span class="name">{{ v.name }}</span>
      </div>
      <div class="basis">
        <div class="basis-info" v-if="hasBasis">
          <span v-for="(v5, i5) in Object.keys(basisFilter)" :key="i5"
            >{{ basisShow[v5] + "：" + basis[v5] }}<br
          /></span>
          <div style="text-align: center; margin-top: 20px">
            <el-button type="primary" size="small" @click="resetAll"
              >再测一次</el-button
            >
          </div>
        </div>
        <div id="eight" @click="handleEightClick" v-else></div>
      </div>
    </div>
    <el-dialog
      custom-class="basis-info-dia"
      title="信息填写"
      :visible.sync="basisInfoDia"
      center
    >
      <el-form
        class="w500"
        :model="basis"
        inline
        label-position="left"
        label-width="150px"
        ref="basis"
      >
        <el-form-item label="性别：" required prop="sex">
          <el-select v-model="basis.sex" placeholder="男/女">
            <el-option label="男" value="男"></el-option>
            <el-option label="女" value="女"></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="年支" required prop="nianzhi">
          <el-select v-model="basis.nianzhi" placeholder="年支">
            <el-option
              v-for="v in dizhi12"
              :key="v"
              :label="v"
              :value="v"
            ></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="年干" required prop="nianzhi">
          <el-select v-model="basis.niangan" placeholder="年干">
            <el-option
              v-for="v in Object.keys(tiangan10)"
              :key="v"
              :label="tiangan10[v]"
              :value="tiangan10[v]"
            ></el-option>
          </el-select>
        </el-form-item>
        <el-form-item label="出生日期（农历）：" required prop="date">
          <el-input
            v-model="basis.date"
            placeholder="格式如：2000/05/07"
            @change="handleBornTimeChange"
          ></el-input>
        </el-form-item>
        <el-form-item label="出生时辰" required prop="hour">
          <el-select v-model="basis.hour" placeholder="时辰">
            <el-option
              v-for="(dz, i) in dizhi12"
              :key="i"
              :label="dz"
              :value="dz"
            ></el-option>
          </el-select>
        </el-form-item>
      </el-form>
      <div slot="footer">
        <el-button type="primary" @click="setBasis">确定</el-button>
        <el-button type="default" @click="resetForm">重置</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
// @ is an alias to /src
import { source } from "@/utils/dataBuild.js";
import { search } from "@/utils/dataHandler.js";
import { dataList, resetDataList } from "@/utils/allData.js";
import { mapGetters } from "vuex";
import { tableData } from "@/utils/dataBuild.js";
export default {
  name: "Home",
  data() {
    return {
      basis: {
        nianzhi: "",
        niangan: "",
        year: "",
        month: "",
        day: "",
        hour: "",
        sex: "",
      },
      resource: null,
      tableList: null,
      basisInfoDia: false,
      hasBasis: false,
      dataList: null,
      dizhi12: source.dizhi12,
      tiangan10: null,
    };
  },
  computed: {
    basisShow() {
      return this.$store.state.basisShow;
    },
    basisFilter() {
      let copyBasis = {};
      let keysShow = Object.keys(this.basisShow);
      console.log("keyShow :>> ", keysShow);
      for (let i in this.basis) {
        if (keysShow.includes(i)) {
          copyBasis[i] = this.basis[i];
        }
      }
      console.log("copyBasis :>> ", copyBasis);
      return copyBasis;
    },
    ...mapGetters(["searchList"]),
  },
  created() {
    this.tiangan10 = {
      jia: "甲",
      yi: "乙",
      bing: "丙",
      ding: "丁",
      wu: "戊",
      ji: "己",
      geng: "庚",
      xin: "辛",
      ren: "壬",
      kui: "癸",
    };
    this.resource = source;
  },
  mounted() {
    this.dataList = dataList;
    this.tableList = Object.keys(tableData);
  },
  methods: {
    setBasis() {
      resetDataList();
      this.$store.commit("SET_BASIS", this.basis);
      this.hasBasis = true;
      console.log("this.$store.state.basis :>> ", this.$store.state.basis);
      let res = [];
      console.log("this.tableList :>> ", this.tableList);
      this.tableList.forEach((name) => {
        res.push(search(...this.$store.getters[name]));
      });
      console.log("res :>> ", res);
      this.insertData(res, this.dataList);
      this.basisInfoDia = false;
    },
    handleBornTimeChange(date) {
      let timeArr = date.split("/");
      console.log("timeArr :>> ", timeArr);
      this.basis.year = +timeArr[0];
      this.basis.month = +timeArr[1];
      this.basis.day = +timeArr[2];
    },
    handleEightClick() {
      this.basisInfoDia = true;
    },
    resetForm() {
      this.$refs.basis.resetFields();
    },
    insertData(source, aim) {
      if (source instanceof Array) {
        source.forEach((item) => {
          this.insertData(item, aim);
        });
      } else if (this.resource.dizhi12.includes(source.pos)) {
        let pos = aim.find((item) => item.name.includes(source.pos));
        console.log("source.pos,pos :>> ", source.pos, pos);
        let key = Object.keys(source)[2];
        console.log("key", key, source[key]);
        if (source.corner < 5) {
          pos.data[`pos${source.corner}`][key] = source[key];
        } else {
          if (source.corner == 5) {
            pos.name = source[key] + pos.name;
          }
        }
      }
    },
    // 重测
    resetAll() {
      resetDataList();
      this.dataList = dataList;
      this.hasBasis = false;
    },
  },
};
</script>
