// 横向规律数据组成行，可调整顺序
function horizonOrderable(first, source, vTitle, ifReverse) {
  const len = source.length;
  let data = {};
  if (ifReverse) {
    let n = vTitle.length - 1;
    for (let i = 0; i < len; i++) {
      // 赋值规律项
      data[vTitle[n - i]] = source[(i + first) % len];
    }
  } else {
    for (let i = 0; i < len; i++) {
      if (vTitle[i]) {
        data[vTitle[i]] = source[(i + first) % len];
      } else {
        break;
      }
    }
  }

  return data;
}
// 纵向规律顺序组成表格
function createByVerticalOrderable(
  capsV,
  capSource,
  len,
  hTitle,
  otherVTitle,
  otherData
) {
  let table = [];
  for (let i = 0; i < len; i++) {
    let obj = {};
    hTitle.forEach((t, index) => {
      obj[t] =
        capSource[(capSource.indexOf(capsV[index]) + i) % capSource.length];
    });
    // 赋值其他项
    otherVTitle.forEach((t, index) => {
      obj[t] = otherData[index][i];
    });
    table.push(obj);
  }
  return table;
}
// 已有数据生成表格：起紫薇表
function createBySpeciallyData(titleList, dataList) {
  let res = [];
  dataList.forEach((row) => {
    let obj = {};
    row.forEach((n, i) => {
      obj[titleList[i]] = n;
    });
    res.push(obj);
  });
  console.log("res :>> ", res);
  return res;
}
// 生成表格,hTitles为每一行的指引标题，vCaps为行的第一列的字符的来源，source为行的数据来源
function creatByHorizon(
  caps,
  source,
  vTitle,
  ifReverse,
  otherVTitle,
  otherData
) {
  let t = [];
  for (let i = 0; i < caps.length; i++) {
    let row = horizonOrderable(
      source.indexOf(caps[i]),
      source,
      vTitle,
      ifReverse
    ); // 生成每一行的数据
    // 赋值其他项
    otherVTitle.forEach((t, index) => {
      row[t] = otherData[index][i];
    });
    t.push(row);
  }
  return t;
}

